// Logout route
app.get('/logout', (req, res) => {
  const idToken = req.session.tokens?.idToken;

  req.session.destroy((err) => {
    if (err) {
      console.error('Session destruction error:', err);
    }

    res.clearCookie('connect.sid');

    // Optionally redirect to OIDC provider's end session endpoint
    const endSessionUrl = `${OIDC_CONFIG.issuer}/logout`;
    const logoutUrl = new URL(endSessionUrl);
    if (idToken) {
      logoutUrl.searchParams.set('id_token_hint', idToken);
    }
    logoutUrl.searchParams.set('post_logout_redirect_uri', 'http://localhost:3000');

    res.redirect(logoutUrl.toString());
  });
});

